const dealsMap = {};

for (const item of $input.all()) {
  const data = item.json;
  const dealId = data.WhatId || data.Id;

  if (!dealsMap[dealId]) {
    dealsMap[dealId] = {
      Id: dealId,
      Amount: data.Amount || 0,
      Probability: data.Probability || 0,
      Type: data.Type || "N/A",
      activities: [],
      allActivitiesCompleted: true
    };
  }

  if (data.Subject) {
    dealsMap[dealId].activities.push({
      subject: data.Subject,
      status: data.Status,
      priority: data.Priority
    });

    //  If ANY activity is not completed → false
    if (data.Status !== "Completed") {
      dealsMap[dealId].allActivitiesCompleted = false;
    }
  }
}

return Object.values(dealsMap).map(deal => ({ json: deal }));

