// Loop over all input items
return $input.all().map(item => {
  const raw = item.json.content?.parts?.[0]?.text;

  // If no content at all
  if (!raw) {
    return { json: {
      deal_id:"null",
      risk_level: "unknown",
      pricing_risk: false,
      delivery_risk: false,
      stakeholder_risk: false,
      summary: "No response received from AI model",
      parse_error: true
    }};
  }

  // Remove ```json and ``` markdown fences
  const cleaned = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  try {
    const parsed = JSON.parse(cleaned);

    // Validate expected fields exist
    const validLevels = ["high", "medium", "low"];
    if (!validLevels.includes(parsed.risk_level)) {
      parsed.risk_level = "unknown";
      parsed.parse_error = true;
      parsed.summary = parsed.summary || "AI returned invalid risk level";
    }

    return { json: parsed };

  } catch (err) {
    // AI response could not be parsed
    return { json: {
      risk_level: "unknown",
      pricing_risk: false,
      delivery_risk: false,
      stakeholder_risk: false,
      summary: "AI response could not be parsed",
      parse_error: true,
      raw_response: raw.slice(0, 300) // first 300 chars for debugging
    }};
  }
});
